import { useState, useEffect } from 'react';
import { Row, Col } from 'react-bootstrap';

function Home() {
  const [mountedAt, setMountedAt] = useState('');

  useEffect(() => {
    setMountedAt(new Date().toLocaleString());
  }, []);

  return (
    <Row className='mt-4'>
      <Col>
        <h2>Home Page</h2>
        <p>Component mounted at: {mountedAt}</p>
      </Col>
    </Row>
  );
}

export default Home;
